function cRank(name) { return CONSENSUS_RANK[name] ?? 99; }
function getMockData(name) {
  const rows = MOCK_DRAFT_DATA[name];
  if (!rows) return null;
  const picks = rows.map(r => r[0]).filter(n => n != null);
  if (!picks.length) return null;
  const avg = picks.reduce((a, b) => a + b, 0) / picks.length;
  return { rows, avg: Math.round(avg * 10) / 10 };
}
function mockDraftAvg(name) {
  const md = getMockData(name);
  return md ? md.avg : 999;
}
function sortedByRank(list) {
  return [...list].sort((a, b) => {
    const aAvg = mockDraftAvg(a.name), bAvg = mockDraftAvg(b.name);
    const aIn = aAvg < 999, bIn = bAvg < 999;
    if (aIn && bIn) return aAvg - bAvg;
    if (aIn) return -1;
    if (bIn) return 1;
    return cRank(a.name) - cRank(b.name);
  });
}

function computeScore(playerPicks, actualPicks) {
  let total = 0;
  const breakdown = [];
  TEAMS.forEach(t => {
    const p = playerPicks[t.pick] || { player: "", lock: false, trade: false };
    const a = actualPicks[t.pick] || { player: "", trade: false };
    if (!a.player) return;
    let pts = 0, reason = "";
    if (p.player && p.player === a.player) {
      pts += 3; reason = "✅ Right team + spot";
      if (p.lock) { const bonus = t.pick >= 4 ? 1 : 0; pts += bonus; if (bonus) reason += " + lock bonus (+1)"; }
      if (p.trade && a.trade) { pts += 1; reason += " + trade nailed (+1)"; }
    } else {
      if (p.trade && a.trade) { pts += 1; reason = "🔄 trade predicted"; }
    }
    if (pts > 0) { total += pts; breakdown.push({ pick: t.pick, team: t.name, player: a.player, predicted: p.player, pts, reason }); }
  });
  return { total, breakdown };
}

function computeFunStats(allPicks, actualPicks) {
  const stats = [];
  const hasActual = Object.values(actualPicks).some(a => a.player);
  if (!hasActual) return [];
  let maxOff = 0, maxOffPlayer = "", maxOffName = "";
  PLAYERS.forEach(player => {
    const pp = allPicks[player] || {};
    Object.entries(pp).forEach(([pickStr, pick]) => {
      if (!pick.player) return;
      const predictedAt = parseInt(pickStr);
      const actualAt = TEAMS.find(t => actualPicks[t.pick]?.player === pick.player)?.pick;
      if (actualAt) { const diff = Math.abs(predictedAt - actualAt); if (diff > maxOff) { maxOff = diff; maxOffPlayer = pick.player; maxOffName = player; } }
    });
  });
  if (maxOff > 0) stats.push({ icon: "🎯", label: "Most off on a player", value: `${maxOffName} missed ${maxOffPlayer} by ${maxOff} spots` });
  PLAYERS.forEach(player => {
    const pp = allPicks[player] || {};
    let uniqueCount = 0;
    Object.values(pp).forEach(pick => {
      if (!pick.player) return;
      const othersHaveSame = PLAYERS.filter(p2 => p2 !== player).some(p2 => Object.values(allPicks[p2] || {}).some(p => p.player === pick.player));
      if (!othersHaveSame) uniqueCount++;
    });
    if (uniqueCount > 0) stats.push({ icon: "🦄", label: `${player}'s contrarian picks`, value: `${uniqueCount} unique picks` });
  });
  TEAMS.forEach(t => {
    const options = PLAYERS.map(p => allPicks[p]?.[t.pick]?.player).filter(Boolean);
    if (options.length === 4 && new Set(options).size === 1) stats.push({ icon: "🤝", label: "Universal consensus", value: `Everyone picked ${options[0]} at #${t.pick}` });
  });
  let bestPick = 999, bestPlayer = "", bestPickName = "";
  PLAYERS.forEach(player => {
    const pp = allPicks[player] || {};
    TEAMS.forEach(t => {
      const p = pp[t.pick];
      if (p?.player && actualPicks[t.pick]?.player === p.player && t.pick < bestPick) { bestPick = t.pick; bestPickName = player; bestPlayer = p.player; }
    });
  });
  if (bestPick < 999) stats.push({ icon: "⚡", label: "Earliest correct pick", value: `${bestPickName} nailed ${bestPlayer} at #${bestPick}` });
  PLAYERS.forEach(player => {
    const pp = allPicks[player] || {};
    TEAMS.forEach(t => {
      const p = pp[t.pick];
      if (p?.player && actualPicks[t.pick]?.player === p.player && t.pick >= 20) stats.push({ icon: "💎", label: "Late-round gem", value: `${player} correctly called ${p.player} at #${t.pick}` });
    });
  });
  return stats.slice(0, 6);
}

const FIREBASE_URL = "https://draft-game-2026-default-rtdb.firebaseio.com/state.json";
async function firebaseGet() {
  try { const res = await fetch(FIREBASE_URL); if (!res.ok) return null; return await res.json(); } catch { return null; }
}
async function firebaseSet(data) {
  try { const res = await fetch(FIREBASE_URL, { method:"PUT", headers:{"Content-Type":"application/json"}, body:JSON.stringify(data) }); return res.ok; } catch { return false; }
}

function makeDefaultState() {
  const picks = {};
  PLAYERS.forEach(p => { picks[p] = {}; TEAMS.forEach(t => { picks[p][t.pick] = { player:"", lock:false, trade:false, tradeTeam:"" }; }); });
  const actual = {};
  TEAMS.forEach(t => { actual[t.pick] = { player:"", trade:false }; });
  const submitted = {};
  PLAYERS.forEach(p => { submitted[p] = false; });
  const scores = {};
  PLAYERS.forEach(p => { scores[p] = 0; });
  return { picks, actual, submitted, scores };
}

const posColors = { QB:"#00e5d4",RB:"#f0b429",WR:"#ff7b40",TE:"#a78bfa",OT:"#34d399",IOL:"#60a5fa",EDGE:"#f87171",DT:"#fb923c",LB:"#e879f9",CB:"#38bdf8",S:"#fbbf24" };

function Avatar({ name, size = 32 }) {
  const [imgOk, setImgOk] = useState(true);
  const prospect = ALL_PROSPECTS.find(p => p.name === name);
  const pos = prospect?.pos || "?";
  const accent = posColors[pos] || "#4a6070";
  const initials = name.split(" ").map(w => w[0]).join("").slice(0,2).toUpperCase();
  const fontSize = size * 0.34;
  const photo = PROSPECT_PHOTOS[name];
  if (photo && imgOk) {
    return (
      <div style={{ width:size, height:size, borderRadius:"50%", overflow:"hidden", flexShrink:0, border:`1.5px solid ${accent}60` }}>
        <img src={photo} alt={name} width={size} height={size} style={{ width:"100%", height:"100%", objectFit:"cover", display:"block" }} onError={() => setImgOk(false)} />
      </div>
    );
  }
  return (
    <div style={{ width:size, height:size, borderRadius:"50%", flexShrink:0, background:`linear-gradient(135deg, #0a1520, #05080b)`, border:`1.5px solid ${accent}60`, display:"flex", alignItems:"center", justifyContent:"center" }}>
      <span style={{ fontFamily:"'Bebas Neue',sans-serif", fontSize, color:accent, lineHeight:1 }}>{initials}</span>
    </div>
  );
}

