function TeamLogo({ espn, size = 24 }) {
  const teamName = ESPN_TO_TEAM[espn];
  const embeddedLogo = teamName ? TEAM_LOGOS[teamName] : null;
  const teamColorMap = { lv:"#a5acaf",nyj:"#125740",ari:"#97233f",ten:"#4b92db",nyg:"#0b2265",cle:"#ff3c00",wsh:"#773141",no:"#d3bc8d",kc:"#e31837",cin:"#fb4f14",mia:"#008e97",dal:"#869397",lar:"#003594",bal:"#241773",tb:"#d50a0a",det:"#0076b6",min:"#4f2683",car:"#0085ca",pit:"#ffb612",lac:"#0080c6",phi:"#004c54",chi:"#c83803",buf:"#00338d",sf:"#aa0000",hou:"#03202f",ne:"#002244",sea:"#69be28" };
  const accent = teamColorMap[espn] || "#4a6070";
  const initials = (espn || "").toUpperCase().slice(0, 3);
  if (embeddedLogo) {
    return <img src={embeddedLogo} alt={teamName} width={size} height={size} style={{ objectFit:"contain", flexShrink:0, borderRadius:4 }} />;
  }
  return (
    <div style={{ width:size, height:size, borderRadius:4, background:`${accent}22`, border:`1px solid ${accent}44`, display:"flex", alignItems:"center", justifyContent:"center" }}>
      <span style={{ fontFamily:"'Bebas Neue',sans-serif", fontSize:size*0.32, color:accent }}>{initials}</span>
    </div>
  );
}

function ProspectPicker({ pickNum, value, locked, usedProspects=[], teamNeeds=[], onChange }) {
  const [open, setOpen] = useState(false);
  const [query, setQuery] = useState("");
  const [posFilter, setPosFilter] = useState(null);
  const [dropRect, setDropRect] = useState(null);
  const triggerRef = useRef(null);
  const dropRef = useRef(null);
  const inputRef = useRef(null);
  useEffect(() => {
    function handler(e) {
      if (triggerRef.current && !triggerRef.current.contains(e.target) && dropRef.current && !dropRef.current.contains(e.target)) setOpen(false);
    }
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, []);
  useEffect(() => {
    if (open) {
      if (inputRef.current) inputRef.current.focus();
      setQuery(""); setPosFilter(null);
      if (triggerRef.current) setDropRect(triggerRef.current.getBoundingClientRect());
    }
  }, [open]);
  useEffect(() => {
    if (!open) return;
    const recalc = () => { if (triggerRef.current) setDropRect(triggerRef.current.getBoundingClientRect()); };
    window.addEventListener("scroll", recalc, true);
    window.addEventListener("resize", recalc);
    return () => { window.removeEventListener("scroll", recalc, true); window.removeEventListener("resize", recalc); };
  }, [open]);
  const prospect = ALL_PROSPECTS.find(p => p.name === value);
  const available = ALL_PROSPECTS.filter(p => p.name === value || !usedProspects.includes(p.name));
  const filtered = sortedByRank(available.filter(p => {
    const matchPos = !posFilter || p.pos === posFilter;
    const matchQuery = !query || p.name.toLowerCase().includes(query.toLowerCase()) || p.school.toLowerCase().includes(query.toLowerCase());
    return matchPos && matchQuery;
  }));
  const allPosInList = [...new Set(available.map(p => p.pos))];
  const needsFirst = [...teamNeeds.filter(n => allPosInList.includes(n)), ...allPosInList.filter(n => !teamNeeds.includes(n))];
  const dropTop = dropRect ? (() => { const spaceBelow = window.innerHeight - dropRect.bottom; const dropH = Math.min(380, window.innerHeight*0.55); return spaceBelow >= dropH+8 ? dropRect.bottom+4 : Math.max(8, dropRect.top-dropH-4); })() : 0;
  const dropLeft = dropRect ? Math.max(8, Math.min(dropRect.left, window.innerWidth-340)) : 0;
  const dropWidth = dropRect ? Math.max(300, dropRect.width) : 300;
  return (
    <div ref={triggerRef} style={{ position:"relative" }}>
      <div onClick={() => !locked && setOpen(o => !o)} style={{ display:"flex", alignItems:"center", gap:8, background:"#05080b", border:"1px solid #1c2a38", borderRadius:8, padding:"7px 10px", cursor:locked?"default":"pointer", minHeight:38 }}>
        {value ? <Avatar name={value} size={26} /> : <div style={{ width:26, height:26, borderRadius:"50%", background:"#0f1720", border:"1px solid #1c2a38" }} />}
        <span style={{ flex:1, fontSize:13, color:value?"#00e5d4":"#4a6070", whiteSpace:"nowrap", overflow:"hidden", textOverflow:"ellipsis" }}>
          {value ? `${value} · ${prospect?.pos} · ${prospect?.school}` : "— Pick a prospect —"}
        </span>
        {!locked && <span style={{ color:"#4a6070", fontSize:11 }}>▾</span>}
      </div>
      {open && dropRect && (
        <div ref={dropRef} style={{ position:"fixed", top:dropTop, left:dropLeft, width:dropWidth, maxHeight:Math.min(380,window.innerHeight*0.55), background:"#0f1720", border:"1px solid #00e5d4", borderRadius:10, zIndex:999999, display:"flex", flexDirection:"column", boxShadow:"0 12px 48px rgba(0,0,0,0.9)" }}>
          <div style={{ padding:"8px 10px 6px", borderBottom:"1px solid #1c2a38", flexShrink:0 }}>
            <input ref={inputRef} value={query} onChange={e => { setQuery(e.target.value); setPosFilter(null); }} placeholder="Search prospects..." onKeyDown={e => e.key==="Escape" && setOpen(false)} style={{ width:"100%", background:"#05080b", border:"1px solid #1c2a38", borderRadius:6, padding:"6px 10px", color:"#dde8f0", fontSize:13, outline:"none" }} />
          </div>
          <div style={{ display:"flex", flex:1, minHeight:0, overflow:"hidden" }}>
            <div style={{ flex:1, overflowY:"auto" }}>
              <div style={{ fontFamily:"'Barlow Condensed',sans-serif", fontSize:10, letterSpacing:1, color:"#4a6070", padding:"6px 10px 2px", textTransform:"uppercase" }}>
                {posFilter ? `${posFilter} prospects` : teamNeeds.length>0 ? `★ needs: ${teamNeeds.slice(0,3).join(", ")}` : "All prospects"}
              </div>
              {filtered.length===0 && <div style={{ padding:14, textAlign:"center", color:"#4a6070", fontSize:13 }}>No prospects found</div>}
              {filtered.map(p => {
                const rank = cRank(p.name);
                const isNeed = teamNeeds.includes(p.pos);
                const md = getMockData(p.name);
                const pc = posColors[p.pos] || "#4a6070";
                return (
                  <div key={p.name} onClick={() => { onChange(p.name); setOpen(false); }} style={{ display:"flex", alignItems:"center", gap:10, padding:"9px 10px", cursor:"pointer", background:p.name===value?"#111d2a":"transparent", borderLeft:isNeed?"3px solid #f0b429":"3px solid transparent" }} onMouseEnter={e => e.currentTarget.style.background="#111d2a"} onMouseLeave={e => e.currentTarget.style.background=p.name===value?"#111d2a":"transparent"}>
                    {/* Photo - bigger */}
                    <Avatar name={p.name} size={44} />
                    {/* Main info */}
                    <div style={{ flex:1, minWidth:0 }}>
                      <div style={{ fontFamily:"'Bebas Neue',sans-serif", fontSize:17, color:"#dde8f0", whiteSpace:"nowrap", overflow:"hidden", textOverflow:"ellipsis", letterSpacing:0.5 }}>{p.name}</div>
                      <div style={{ display:"flex", alignItems:"center", gap:6, marginTop:1 }}>
                        <span style={{ fontFamily:"'Bebas Neue',sans-serif", fontSize:13, background:`${pc}22`, color:pc, borderRadius:4, padding:"1px 6px" }}>{p.pos}</span>
                        <span style={{ fontFamily:"'Barlow Condensed',sans-serif", fontSize:12, color:"#4a6070" }}>{p.school}</span>
                      </div>
                      {(() => {
                        const cd = COMBINE_DATA[p.name];
                        if (!cd || (!cd.forty && !cd.bench && !cd.cone)) return null;
                        return (
                          <div style={{ display:"flex", gap:6, marginTop:3 }}>
                            {cd.forty && <div style={{ fontFamily:"'Barlow Condensed',sans-serif", fontSize:10, color:"#00e5d4", background:"rgba(0,229,212,0.08)", borderRadius:3, padding:"1px 5px" }}>⚡{cd.forty}</div>}
                            {cd.bench && <div style={{ fontFamily:"'Barlow Condensed',sans-serif", fontSize:10, color:"#f0b429", background:"rgba(240,180,41,0.08)", borderRadius:3, padding:"1px 5px" }}>💪{cd.bench}</div>}
                            {cd.cone && <div style={{ fontFamily:"'Barlow Condensed',sans-serif", fontSize:10, color:"#a855f7", background:"rgba(168,85,247,0.08)", borderRadius:3, padding:"1px 5px" }}>🔺{cd.cone}</div>}
                          </div>
                        );
                      })()}
                      {md && (
                        <div style={{ display:"flex", gap:3, flexWrap:"wrap", marginTop:3 }}>
                          {MOCK_DRAFT_SOURCES.map((src, i) => {
                            const row = md.rows[i];
                            if (!row || row[0]==null) return null;
                            const [pick, team] = row;
                            const pickColor = pick<=10?"#f0b429":pick<=20?"#00e5d4":"#4a6070";
                            return (
                              <div key={src} style={{ display:"flex", alignItems:"center", gap:1, background:"#0a1520", borderRadius:3, padding:"1px 4px" }}>
                                <span style={{ fontFamily:"'Barlow Condensed',sans-serif", fontSize:8, color:"#4a6070" }}>{src}</span>
                                <span style={{ fontFamily:"'Bebas Neue',sans-serif", fontSize:10, color:pickColor }}>#{pick}</span>
                              </div>
                            );
                          })}
                        </div>
                      )}
                    </div>
                    {/* Right side: consensus rank small, avg big */}
                    <div style={{ display:"flex", flexDirection:"column", alignItems:"flex-end", gap:3, flexShrink:0 }}>
                      {rank<=66 && <div style={{ fontFamily:"'Barlow Condensed',sans-serif", fontSize:9, color:"#2a3a4a", letterSpacing:1 }}>#{rank}</div>}
                      {md && <div style={{ fontFamily:"'Bebas Neue',sans-serif", fontSize:18, color:"#f0b429", lineHeight:1 }}>#{md.avg}<div style={{ fontFamily:"'Barlow Condensed',sans-serif", fontSize:8, color:"#4a6070", textAlign:"right", letterSpacing:1 }}>AVG</div></div>}
                    </div>
                  </div>
                );
              })}
            </div>
            <div style={{ width:52, borderLeft:"1px solid #1c2a38", display:"flex", flexDirection:"column", overflowY:"auto", gap:2, padding:4 }}>
              <button onClick={() => setPosFilter(null)} style={{ fontFamily:"'Barlow Condensed',sans-serif", fontSize:10, border:"none", borderRadius:4, padding:"4px 2px", cursor:"pointer", background:!posFilter?"#1c2a38":"transparent", color:!posFilter?"#00e5d4":"#4a6070" }}>ALL</button>
              {needsFirst.map(pos => {
                const isNeed = teamNeeds.includes(pos);
                const active = posFilter===pos;
                return (
                  <button key={pos} onClick={() => setPosFilter(active?null:pos)} style={{ fontFamily:"'Barlow Condensed',sans-serif", fontSize:10, border:"none", borderRadius:4, padding:"4px 2px", cursor:"pointer", background:active?"#1c2a38":"transparent", color:active?"#00e5d4":isNeed?"#f0b429":"#4a6070", textAlign:"center" }}>
                    {pos}{isNeed && <div style={{ fontSize:8, color:"#f0b429" }}>★</div>}
                  </button>
                );
              })}
            </div>
          </div>
          {value && (
            <div onClick={() => { onChange(""); setOpen(false); }} style={{ padding:"6px 12px", cursor:"pointer", color:"#ff3d57", fontFamily:"'Barlow Condensed',sans-serif", fontSize:12, letterSpacing:1, background:"#0a0f14", borderTop:"1px solid #1c2a38", textAlign:"center" }} onMouseEnter={e => e.currentTarget.style.background="rgba(255,61,87,0.08)"} onMouseLeave={e => e.currentTarget.style.background="#0a0f14"}>✕ Clear selection</div>
          )}
        </div>
      )}
    </div>
  );
}

function Confetti() {
  const pieces = Array.from({ length:80 }, (_, i) => ({ id:i, x:Math.random()*100, delay:Math.random()*0.8, dur:2.5+Math.random()*1.5, color:["#00e5d4","#f0b429","#ff7b40","#00d084","#fff","#ff3d57"][Math.floor(Math.random()*6)], size:6+Math.random()*8, drift:(Math.random()-0.5)*200 }));
  return (
    <div style={{ position:"fixed", inset:0, pointerEvents:"none", zIndex:99999, overflow:"hidden" }}>
      <style>{`@keyframes confettiFall{0%{transform:translateY(-20px) rotate(0deg);opacity:1}100%{transform:translateY(110vh) rotate(720deg);opacity:0}}`}</style>
      {pieces.map(p => <div key={p.id} style={{ position:"absolute", left:`${p.x}%`, top:0, width:p.size, height:p.size*0.5, background:p.color, borderRadius:2, animation:`confettiFall ${p.dur}s ${p.delay}s ease-in forwards`, transform:`translateX(${p.drift}px)` }} />)}
      <div style={{ position:"absolute", top:"38%", left:"50%", transform:"translate(-50%,-50%)", textAlign:"center" }}>
        <div style={{ fontFamily:"'Bebas Neue',sans-serif", fontSize:64, color:"#f0b429", textShadow:"0 0 40px #f0b42988" }}>BOARD COMPLETE! 🏈</div>
        <div style={{ fontFamily:"'Barlow Condensed',sans-serif", fontSize:20, color:"#dde8f0", letterSpacing:2 }}>32 picks locked in</div>
      </div>
    </div>
  );
}

